def solve(n: Long, edges: Array[Array[Long]], label: String): Long = {
    val n_node = n.toInt
    val graph = Array.fill(n_node)(List[Int]())
    for (edge <- edges) {
        val u = edge(0).toInt
        val v = edge(1).toInt
        graph(u) = v :: graph(u)
        graph(v) = u :: graph(v)
    }

    val total_mask = 1 << n_node
    val dp = Array.ofDim[Int](total_mask, n_node, n_node)
    for {
        mask <- 0 until total_mask
        u <- 0 until n_node
        v <- 0 until n_node
    } dp(mask)(u)(v) = 0

    for (i <- 0 until n_node) {
        val mask = 1 << i
        dp(mask)(i)(i) = 1
    }

    for (edge <- edges) {
        val u = edge(0).toInt
        val v = edge(1).toInt
        if (label.charAt(u) == label.charAt(v)) {
            val mask = (1 << u) | (1 << v)
            if (dp(mask)(u)(v) < 2) dp(mask)(u)(v) = 2
            if (dp(mask)(v)(u) < 2) dp(mask)(v)(u) = 2
        }
    }

    var ans = 0
    for (mask <- 0 until total_mask) {
        for (u <- 0 until n_node) {
            for (v <- 0 until n_node) {
                val current = dp(mask)(u)(v)
                if (current > 0) {
                    if (current > ans) ans = current
                    for (w <- graph(u)) {
                        if ((mask & (1 << w)) == 0) {
                            for (x <- graph(v)) {
                                if ((mask & (1 << x)) == 0 && w != x && label.charAt(w) == label.charAt(x)) {
                                    val new_mask = mask | (1 << w) | (1 << x)
                                    val new_val = current + 2
                                    if (new_val > dp(new_mask)(w)(x)) {
                                        dp(new_mask)(w)(x) = new_val
                                    }
                                }
                            }
                        }
                    }
                }
            }
        }
    }
    ans.toLong
}
