import scala.collection.mutable.ArrayBuffer

def solve(n: Long, edges: Array[Array[Long]], label: String): Long = {
  val numNodes = n.toInt
  val adj: Array[ArrayBuffer[Int]] = Array.fill(numNodes)(ArrayBuffer[Int]())

  for (edge <- edges) {
    val u = edge(0).toInt
    val v = edge(1).toInt
    adj(u) += v
    adj(v) += u
  }

  val totalMasks = 1 << numNodes
  val dp = Array.ofDim[Boolean](totalMasks, numNodes, numNodes)
  var best: Long = 0

  for (i <- 0 until numNodes) {
    val mask = 1 << i
    dp(mask)(i)(i) = true
    best = math.max(best, 1)
  }

  for (edge <- edges) {
    val u = edge(0).toInt
    val v = edge(1).toInt
    if (label.charAt(u) == label.charAt(v)) {
      val mask = (1 << u) | (1 << v)
      if (!dp(mask)(u)(v)) {
        dp(mask)(u)(v) = true
        best = math.max(best, 2)
      }
      if (!dp(mask)(v)(u)) {
        dp(mask)(v)(u) = true
        best = math.max(best, 2)
      }
    }
  }

  val masksByPopcount = Array.fill(numNodes + 1)(ArrayBuffer[Int]())
  for (mask <- 0 until totalMasks) {
    val cnt = java.lang.Integer.bitCount(mask)
    if (cnt >= 1 && cnt <= numNodes) {
      masksByPopcount(cnt) += mask
    }
  }

  for (size <- 1 until numNodes) {
    for (mask <- masksByPopcount(size)) {
      for (i <- 0 until numNodes) {
        for (j <- 0 until numNodes) {
          if (dp(mask)(i)(j)) {
            for (k <- adj(i)) {
              if ((mask & (1 << k)) == 0) {
                if (label.charAt(k) == label.charAt(j)) {
                  val newMask = mask | (1 << k)
                  if (!dp(newMask)(k)(j)) {
                    dp(newMask)(k)(j) = true
                    best = math.max(best, size + 1)
                  }
                }
              }
            }
            for (k <- adj(j)) {
              if ((mask & (1 << k)) == 0) {
                if (label.charAt(k) == label.charAt(i)) {
                  val newMask = mask | (1 << k)
                  if (!dp(newMask)(i)(k)) {
                    dp(newMask)(i)(k) = true
                    best = math.max(best, size + 1)
                  }
                }
              }
            }
          }
        }
      }
    }
  }

  best
}
